using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver (resolves any type)
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1. GetTypeInfo<T>() — returns JsonTypeInfo<T> directly, no cast needed
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> => Type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"  Serialized: {json}");

// 2. TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? resolvedInfo))
{
    Console.WriteLine($"TryGetTypeInfo<Person> => resolved: {resolvedInfo!.Type.Name}");
}

// Now show a case where metadata is NOT available.
// Use a source-gen context that only knows about Person.
var restricted = new JsonSerializerOptions { TypeInfoResolver = AppJsonContext.Default };

if (restricted.TryGetTypeInfo<Order>(out JsonTypeInfo<Order>? orderInfo))
{
    Console.WriteLine($"TryGetTypeInfo<Order> => resolved (unexpected)");
}
else
{
    Console.WriteLine($"TryGetTypeInfo<Order> => not available (no exception thrown)");
}

// Types
public record Person(string Name, int Age);
public record Order(int Id, decimal Total);

// Source-gen context that only includes Person
[JsonSerializable(typeof(Person))]
public partial class AppJsonContext : JsonSerializerContext;

